import json
import os
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
from datetime import datetime
import hashlib
import re
from typing import Dict, Any

# Initialize clients with least privilege principle
storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

# Configuration with validation
PROJECT_ID = os.environ.get('GCP_PROJECT')
PUBSUB_TOPIC = os.environ.get('PUBSUB_TOPIC')
FIRESTORE_COLLECTION = os.environ.get('FIRESTORE_COLLECTION', 'processed_files')

# Allowlist for file types
ALLOWED_EXTENSIONS = {'.txt', '.json', '.csv', '.log'}
MAX_FILE_SIZE = 10 * 1024 * 1024  # 10MB limit

def validate_bucket_name(bucket_name: str) -> bool:
    """Validate bucket name against expected pattern"""
    pattern = r'^[a-z0-9][a-z0-9-_]{1,61}[a-z0-9]$'
    return bool(re.match(pattern, bucket_name))

def validate_file_path(file_path: str) -> bool:
    """Validate file path to prevent path traversal"""
    if '..' in file_path or file_path.startswith('/'):
        return False
    return True

def sanitize_filename(filename: str) -> str:
    """Sanitize filename to prevent injection attacks"""
    return re.sub(r'[^a-zA-Z0-9._-]', '_', filename)

def validate_file_extension(filename: str) -> bool:
    """Check if file extension is allowed"""
    _, ext = os.path.splitext(filename.lower())
    return ext in ALLOWED_EXTENSIONS

def compute_file_hash(content: bytes) -> str:
    """Compute SHA-256 hash of file content"""
    return hashlib.sha256(content).hexdigest()

def process_file_content(content: bytes, content_type: str) -> Dict[str, Any]:
    """Process file content based on type with size limits"""
    if len(content) > MAX_FILE_SIZE:
        raise ValueError(f"File size exceeds maximum allowed size of {MAX_FILE_SIZE} bytes")
    
    try:
        if content_type == 'application/json':
            return json.loads(content.decode('utf-8'))
        elif content_type == 'text/plain' or content_type == 'text/csv':
            return {'content': content.decode('utf-8')[:10000]}  # Limit text content
        else:
            return {'content_type': content_type, 'size': len(content)}
    except Exception as e:
        return {'error': f'Failed to process content: {str(e)}', 'size': len(content)}

def write_to_firestore(data: Dict[str, Any], collection: str) -> str:
    """Write data to Firestore with input validation"""
    if not collection or not isinstance(collection, str):
        raise ValueError("Invalid collection name")
    
    # Sanitize collection name
    collection = re.sub(r'[^a-zA-Z0-9_-]', '_', collection)
    
    # Limit document size
    data_str = json.dumps(data)
    if len(data_str) > 1000000:  # 1MB Firestore limit
        raise ValueError("Document size exceeds Firestore limit")
    
    doc_ref = firestore_client.collection(collection).document()
    doc_ref.set(data)
    return doc_ref.id

def publish_to_pubsub(message_data: Dict[str, Any], topic_path: str) -> str:
    """Publish message to Pub/Sub with validation"""
    if not topic_path:
        raise ValueError("Topic path is required")
    
    # Validate topic path format
    if not re.match(r'^projects/[^/]+/topics/[^/]+$', topic_path):
        raise ValueError("Invalid topic path format")
    
    message_json = json.dumps(message_data)
    message_bytes = message_json.encode('utf-8')
    
    # Pub/Sub message size limit is 10MB
    if len(message_bytes) > 10 * 1024 * 1024:
        raise ValueError("Message size exceeds Pub/Sub limit")
    
    future = publisher.publish(topic_path, message_bytes)
    return future.result()

def process_storage_file(event: Dict[str, Any], context: Any) -> None:
    """
    Cloud Function triggered by Cloud Storage events.
    Implements security best practices with least privilege access.
    """
    try:
        # Validate required environment variables
        if not PROJECT_ID:
            raise ValueError("GCP_PROJECT environment variable not set")
        if not PUBSUB_TOPIC:
            raise ValueError("PUBSUB_TOPIC environment variable not set")
        
        # Extract and validate event data
        bucket_name = event.get('bucket')
        file_name = event.get('name')
        
        if not bucket_name or not file_name:
            raise ValueError("Missing bucket or file name in event")
        
        # Validate inputs
        if not validate_bucket_name(bucket_name):
            raise ValueError(f"Invalid bucket name: {bucket_name}")
        
        if not validate_file_path(file_name):
            raise ValueError(f"Invalid file path: {file_name}")
        
        if not validate_file_extension(file_name):
            raise ValueError(f"File type not allowed: {file_name}")
        
        # Sanitize filename
        safe_filename = sanitize_filename(os.path.basename(file_name))
        
        # Get file from Cloud Storage with size check
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        # Check file size before downloading
        if blob.size and blob.size > MAX_FILE_SIZE:
            raise ValueError(f"File size {blob.size} exceeds maximum allowed size")
        
        file_content = blob.download_as_bytes()
        content_type = blob.content_type or 'application/octet-stream'
        
        # Compute file hash for integrity
        file_hash = compute_file_hash(file_content)
        
        # Process file content
        processed_data = process_file_content(file_content, content_type)
        
        # Prepare Firestore document with metadata
        firestore_data = {
            'original_filename': safe_filename,
            'bucket': bucket_name,
            'file_path': file_name,
            'content_type': content_type,
            'file_size': len(file_content),
            'file_hash': file_hash,
            'processed_at': firestore.SERVER_TIMESTAMP,
            'event_id': context.event_id if context else None,
            'processed_content': processed_data
        }
        
        # Write to Firestore
        doc_id = write_to_firestore(firestore_data, FIRESTORE_COLLECTION)
        
        # Prepare Pub/Sub message
        pubsub_message = {
            'document_id': doc_id,
            'filename': safe_filename,
            'bucket': bucket_name,
            'file_hash': file_hash,
            'processed_at': datetime.utcnow().isoformat(),
            'status': 'success'
        }
        
        # Construct topic path
        topic_path = f'projects/{PROJECT_ID}/topics/{PUBSUB_TOPIC}'
        
        # Publish to Pub/Sub
        message_id = publish_to_pubsub(pubsub_message, topic_path)
        
        print(f"Successfully processed file: {safe_filename}")
        print(f"Firestore document ID: {doc_id}")
        print(f"Pub/Sub message ID: {message_id}")
        
    except Exception as e:
        error_message = f"Error processing file: {str(e)}"
        print(error_message)
        
        # Attempt to log error to Pub/Sub if possible
        try:
            if PROJECT_ID and PUBSUB_TOPIC:
                error_data = {
                    'status': 'error',
                    'error_message': str(e),
                    'filename': event.get('name', 'unknown'),
                    'bucket': event.get('bucket', 'unknown'),
                    'timestamp': datetime.utcnow().isoformat()
                }
                topic_path = f'projects/{PROJECT_ID}/topics/{PUBSUB_TOPIC}'
                publish_to_pubsub(error_data, topic_path)
        except Exception as pub_error:
            print(f"Failed to publish error message: {str(pub_error)}")
        
        raise

# HTTP-triggered version for testing
def http_trigger(request):
    """HTTP Cloud Function for manual testing"""
    try:
        request_json = request.get_json(silent=True)
        
        if not request_json:
            return {'error': 'Invalid request body'}, 400
        
        # Validate required fields
        required_fields = ['bucket', 'name']
        if not all(field in request_json for field in required_fields):
            return {'error': 'Missing required fields: bucket, name'}, 400
        
        # Create mock context
        class MockContext:
            event_id = 'http-trigger'
        
        process_storage_file(request_json, MockContext())
        
        return {'status': 'success', 'message': 'File processed successfully'}, 200
        
    except Exception as e:
        return {'error': str(e)}, 500